import { RepoType } from '../contract.js';

export const checkId = 'health-check';
export const name = 'Health Check Route';
export const appliesTo = ['deployable', 'server', 'framework'];

const SERVER_DEPS = new Set([
  'express', 'fastify', 'koa', 'restify', 'polka', 'connect', 'hapi', '@hapi/hapi',
  'micro', 'http-server', 'serve-static', 'json-server', 'next', 'nuxt', 'astro',
  '@astrojs/node', 'remix', 'nitropack', 'nitro', 'h3', 'hono', 'elysia',
  '@nestjs/core', '@nestjs/common', '@nestjs/platform-express', '@nestjs/platform-fastify',
  'cloudflare', '@cloudflare/workers-types', 'wrangler', 'worktop', 'itty-router',
]);

const HEALTH_LIBS = new Set([
  '@godaddy/terminus', 'lightship', 'terminus', 'express-actuator',
  '@nestjs/terminus', 'under-pressure',
]);

const HEALTH_CODE_PATTERNS = [
  /\.(get|post|put|delete|all|use)\s*\(\s*['"`]\/healthz?\b/i,
  /\.(get|post|put|delete|all|use)\s*\(\s*['"`]\/status\b/i,
  /\.(get|post|put|delete|all|use)\s*\(\s*['"`]\/ready\b/i,
  /\.(get|post|put|delete|all|use)\s*\(\s*['"`]\/alive\b/i,
  /\.(get|post|put|delete|all|use)\s*\(\s*['"`]\/ping\b/i,
  /pathname\s*===?\s*['"`]\/health/i,
  /pathname\s*===?\s*['"`]\/status/i,
  /pathname\s*===?\s*['"`]\/ready/i,
  /event\.(path|node\.req\.url).*(health|status|ready|alive|ping)/i,
  /@Get\s*\(['"`]health['"`]\)/i,
  /@Controller\s*\(['"`]health['"`]\)/i,
  /lightship|terminus|under-pressure|express-actuator/i,
  /livenessProbe|readinessProbe|startupProbe/i,
];

function hasServerDependency(packageJson) {
  if (!packageJson) return false;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies, ...packageJson.peerDependencies };
  return Object.keys(deps).some(d => SERVER_DEPS.has(d));
}

function findHealthDependency(packageJson) {
  if (!packageJson) return null;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies, ...packageJson.peerDependencies };
  return Object.keys(deps).find(d => HEALTH_LIBS.has(d)) || null;
}

function hasStartScript(packageJson) {
  if (!packageJson?.scripts) return false;
  const s = packageJson.scripts;
  return !!(s.start || s.serve || s.deploy || s.preview || s['start:prod'] || s['start:production']);
}

function hasDeploymentConfig(tree) {
  return tree.some(p => {
    const lower = p.toLowerCase();
    return /^dockerfile/.test(lower) ||
      /^docker-compose\.(yml|yaml)$/.test(lower) ||
      /^fly\.toml$/.test(lower) ||
      /^wrangler\.(toml|json)$/.test(lower) ||
      /^serverless\.(yml|yaml|json|ts)$/.test(lower) ||
      /^app\.(ya?ml)$/.test(lower) ||
      /^captain-definition$/.test(lower) ||
      /^Procfile$/.test(lower) ||
      (/(^|\/)(k8s|kubernetes|helm|deploy|infra)\//.test(p) && /\.(ya?ml|yaml|json|toml)$/.test(lower));
  });
}

function hasApiRoutesDir(tree) {
  return tree.some(p => /(^|\/)((app|pages)\/api|api\/|server\/api|src\/api)\//i.test(p)) ||
    tree.some(p => /(^|\/)((src\/)?(server|controllers|handlers|middleware|backend|workers|netlify\/functions|supabase\/functions|edge-functions))\//i.test(p));
}

function hasRootServerFile(tree) {
  return tree.some(p => /^(src\/)?(server|app|main|index)\.(js|ts|mjs|cjs)$/.test(p));
}

function isClearlyServer(packageJson, tree) {
  let score = 0;
  if (hasServerDependency(packageJson)) score += 3;
  if (hasDeploymentConfig(tree)) score += 3;
  if (hasStartScript(packageJson)) score += 2;
  if (hasApiRoutesDir(tree)) score += 2;
  if (hasRootServerFile(tree)) score += 1;
  return score >= 2;
}

function scoreServerFile(path) {
  let score = 0;
  const lower = path.toLowerCase();
  const basename = lower.split('/').pop();

  if (/^(src\/)?(server|app|main|index)\.(js|ts|mjs|cjs)$/.test(path)) score += 15;
  if (/(^|\/)((app|pages)\/api|api\/)/.test(path)) score += 12;
  if (/(^|\/)((src\/)?api|server\/api)\//.test(path)) score += 10;
  if (/(^|\/)((src\/)?routes|server|routes)\//.test(path)) score += 8;
  if (/(^|\/)((src\/)?(controllers|handlers|middleware|backend|workers))\//.test(path)) score += 7;
  if (/(^|\/)((netlify|supabase|edge)[-_]?functions|functions)\//.test(path)) score += 8;
  if (/\.(route|router|controller|handler|endpoint|middleware)\./.test(basename)) score += 5;
  if (path.startsWith('src/')) score += 2;

  if (/\.(test|spec)\./.test(path)) score -= 25;
  if (/(__tests__|__mocks__|fixtures?|examples?|demo|playground|benchmark|docs|\.github|\.storybook|scripts|dist|build|coverage|storybook|bin|cli|config|vitest|jest|knip|lint|\.vscode)\//i.test(path)) score -= 15;
  if (/node_modules/.test(path)) score -= 50;
  if (/\.d\.ts$/.test(path)) score -= 30;

  const depth = path.split('/').length;
  if (depth > 6) score -= 3;
  if (depth > 10) score -= 6;

  return score;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    const clearlyServer = isClearlyServer(packageJson, tree);

    if (repoType === RepoType.LIBRARY || repoType === RepoType.EMPTY) {
      if (!clearlyServer) {
        return {
          checkId,
          status: 'not-applicable',
          confidence: 'high',
          message: 'Library or empty repository without server or deployment signals',
          findings: [],
        };
      }
    }

    if (repoType === 'framework') {
      const hasAppSignals = clearlyServer ||
        tree.some(p => /^apps\/[^/]+\/(api|server|routes|middleware|controllers|handlers)/i.test(p)) ||
        tree.some(p => /^(app|server|api)\//i.test(p));

      if (!hasAppSignals) {
        return {
          checkId,
          status: 'not-applicable',
          confidence: 'high',
          message: 'Framework source repository without deployed application signals',
          findings: [],
        };
      }
    }

    if (!clearlyServer) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'medium',
        message: 'No server-side code or deployment infrastructure detected',
        findings: [],
      };
    }

    const findings = [];

    if (packageJson?.scripts) {
      for (const [scriptName] of Object.entries(packageJson.scripts)) {
        if (/^(health|healthcheck|status|ping|ready|alive)/i.test(scriptName)) {
          return {
            checkId,
            status: 'pass',
            confidence: 'high',
            message: `Health check script found: "${scriptName}"`,
            findings: [{ file: 'package.json', issue: `Script "${scriptName}" indicates a health endpoint` }],
          };
        }
      }
    }

    const healthLib = findHealthDependency(packageJson);
    if (healthLib) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: `Health check library present: ${healthLib}`,
        findings: [{ file: 'package.json', issue: `Uses ${healthLib}` }],
      };
    }

    const infraCandidates = tree.filter(p => {
      const lower = p.toLowerCase();
      return /^dockerfile/.test(lower) ||
        /^docker-compose\.(yml|yaml)$/.test(lower) ||
        /^fly\.toml$/.test(lower) ||
        /^wrangler\.(toml|json)$/.test(lower) ||
        /^serverless\.(yml|yaml|json|ts)$/.test(lower) ||
        /^app\.(ya?ml)$/.test(lower) ||
        /^captain-definition$/.test(lower) ||
        /^Procfile$/.test(lower) ||
        (/(^|\/)(k8s|kubernetes|helm|deploy|infra)\//.test(p) && /\.(ya?ml|yaml|json|toml)$/.test(lower)) ||
        (/\.github\/workflows\//.test(p) && /\.(ya?ml|yaml)$/.test(lower));
    }).slice(0, 10);

    for (const filePath of infraCandidates) {
      const content = await files.get(filePath);
      if (!content) continue;

      const hasHealthSignal =
        (/\b(HEALTHCHECK|healthcheck|health-check)\b/i.test(content)) ||
        (/\b(livenessProbe|readinessProbe|startupProbe)\b/i.test(content)) ||
        (/(\/health|\/status|\/ready|\/alive|\/ping)\b/i.test(content));

      if (hasHealthSignal) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Health probe or check configured in ${filePath}`,
          findings: [{ file: filePath, issue: 'Deployment config references health endpoint or probe' }],
        };
      }
    }

    const healthNameRe = /(health|healthcheck|health-check|healthz|status|ready|alive|ping)/i;
    const serverDirRe = /(^|\/)((src\/)?(api|server|controllers|handlers|middleware|backend|workers|functions|netlify\/functions|supabase\/functions|edge-functions|routes|pages\/api|app\/api|app\/health|pages\/health))\//i;

    const healthFileCandidates = tree.filter(p => {
      const basename = p.split('/').pop();
      return healthNameRe.test(basename) &&
        serverDirRe.test(p) &&
        /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) &&
        !/\.d\.ts$/.test(p);
    }).slice(0, 8);

    for (const filePath of healthFileCandidates) {
      const content = await files.get(filePath);
      if (content && content.trim().length > 0) {
        const isRouteLike = /(export\s+(default\s+)?(async\s+)?function|export\s+const|module\.exports|exports\.|app\.(get|post|use|all)|router\.|defineEventHandler|@Get|@Controller|export\s+(async\s+)?function\s+(loader|action))/i.test(content);
        if (isRouteLike) {
          return {
            checkId,
            status: 'pass',
            confidence: 'high',
            message: `Health endpoint file found: ${filePath}`,
            findings: [{ file: filePath, issue: 'Dedicated health route file with handlers' }],
          };
        }
      }
    }

    const codeCandidates = tree
      .filter(p => /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) && !/\.d\.ts$/.test(p) && !/node_modules/.test(p))
      .map(p => ({ path: p, score: scoreServerFile(p) }))
      .filter(f => f.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 10)
      .map(f => f.path);

    if (codeCandidates.length === 0) {
      const fallback = tree.filter(p => /^(src\/)?(server|app|main|index)\.(js|ts|mjs|cjs)$/.test(p)).slice(0, 3);
      codeCandidates.push(...fallback);
    }

    let foundFile = null;
    for (const filePath of codeCandidates) {
      const content = await files.get(filePath);
      if (!content) {
        findings.push({ file: filePath, issue: 'Could not read file content' });
        continue;
      }

      for (const pattern of HEALTH_CODE_PATTERNS) {
        if (pattern.test(content)) {
          foundFile = filePath;
          break;
        }
      }

      if (foundFile) {
        findings.push({ file: filePath, issue: 'Health endpoint pattern matched in source' });
        break;
      } else {
        findings.push({ file: filePath, issue: 'Scanned for health endpoint — none found' });
      }
    }

    if (foundFile) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: `Health check endpoint detected in ${foundFile}`,
        findings,
      };
    }

    return {
      checkId,
      status: 'fail',
      confidence: 'high',
      message: 'Server or deployment infrastructure detected, but no health check endpoint or probe found',
      findings: findings.length > 0 ? findings : [{ file: 'N/A', issue: 'No health endpoint detected after scanning relevant files' }],
    };

  } catch (err) {
    console.error(`[${checkId}] analysis error:`, err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during health check analysis: ${err.message}`,
      findings: [{ file: 'N/A', issue: `Error: ${err.message}` }],
    };
  }
}
